// Support both webhook payload and Drive trigger
const webhookData = $input.first()?.json?.body || $input.first()?.json || {};

// Build case record
const caseId = webhookData.caseId
  || `CASE-${new Date().getFullYear()}-${Math.random().toString(36).substr(2,6).toUpperCase()}`;

const documents = webhookData.documents || [];

// If triggered from Drive (no documents array), build a single-doc list
const finalDocs = documents.length > 0 ? documents : [{
  name: webhookData.name || 'Unknown Document',
  type: 'unknown',
  driveFileId: webhookData.id || webhookData.driveFileId || null,
  url: webhookData.webViewLink || null
}];

const caseRecord = {
  caseId,
  submitterEmail: webhookData.submitterEmail || webhookData.owners?.[0]?.emailAddress || 'user@example.com',
  propertyAddress: webhookData.propertyAddress || webhookData.property_address || 'Address not provided',
  transactionType: (webhookData.transactionType || 'sale').toUpperCase(),
  jurisdiction: (webhookData.jurisdiction || 'NSW').toUpperCase(),
  submittedAt: new Date().toISOString(),
  totalDocuments: finalDocs.length,
  runId: `RUN-${Date.now()}`
};

// Emit one item per document so next nodes process in parallel
return finalDocs.map(doc => ({
  json: {
    case: caseRecord,
    document: {
      docId: `DOC-${Math.random().toString(36).substr(2,8).toUpperCase()}`,
      name: doc.name || 'Unnamed',
      declaredType: (doc.type || 'unknown').toLowerCase(),
      driveFileId: doc.driveFileId || doc.id || null,
      url: doc.url || null,
      fileExtension: (doc.name || '').split('.').pop()?.toLowerCase() || 'pdf'
    }
  }
}));

const docMeta = $('Register Validation Case').item.json;
const rawText = $('Extract Document Text').item?.json?.text
  || $('Download Document from Drive').item?.json?.error
  || 'TEXT_EXTRACTION_FAILED';

// Simple keyword-based classifier as fallback to declared type
const text = (rawText || '').toLowerCase().substring(0, 3000);
const detectedType = (() => {
  if (text.includes('contract of sale') || text.includes('agreement for sale') || text.includes('purchase price')) return 'CONTRACT_OF_SALE';
  if (text.includes('certificate of title') || text.includes('folio identifier') || text.includes('torrens title')) return 'CERTIFICATE_OF_TITLE';
  if (text.includes('section 32') || text.includes('vendor statement') || text.includes('vendor disclosure')) return 'VENDOR_DISCLOSURE';
  if (text.includes('strata') || text.includes('body corporate') || text.includes('owners corporation')) return 'STRATA_REPORT';
  if (text.includes('building inspection') || text.includes('pest inspection') || text.includes('structural')) return 'BUILDING_PEST_REPORT';
  if (text.includes('zoning') || text.includes('planning certificate') || text.includes('10.7')) return 'PLANNING_CERTIFICATE';
  if (text.includes('land tax') || text.includes('revenue nsw') || text.includes('state revenue')) return 'LAND_TAX_CERTIFICATE';
  if (text.includes('mortgage') || text.includes('discharge') || text.includes('encumbrance')) return 'MORTGAGE_DOCUMENT';
  if (text.includes('lease') || text.includes('tenancy') || text.includes('residential tenancies')) return 'LEASE_AGREEMENT';
  if (text.includes('council rates') || text.includes('local government') || text.includes('municipal')) return 'RATES_NOTICE';
  if (text.includes('smoke alarm') || text.includes('safety switch') || text.includes('pool safety')) return 'SAFETY_CERTIFICATE';
  return docMeta.document.declaredType?.toUpperCase().replace(/ /g,'_') || 'UNKNOWN';
})();

// Check for potential expiry dates
const expiryPatterns = [
  /expir(?:y|es|ed)\s*:?\s*([\d]{1,2}[\/-][\d]{1,2}[\/-][\d]{2,4})/gi,
  /valid until\s*:?\s*([\d]{1,2}[\/-][\d]{1,2}[\/-][\d]{2,4})/gi,
  /valid to\s*:?\s*([\d]{1,2}[\/-][\d]{1,2}[\/-][\d]{2,4})/gi
];
const expiryMatches = [];
for (const pattern of expiryPatterns) {
  const match = rawText.match(pattern);
  if (match) expiryMatches.push(...match.slice(0,2));
}

return {
  json: {
    case: docMeta.case,
    document: {
      ...docMeta.document,
      detectedType,
      textLength: rawText.length,
      textPreview: rawText.substring(0, 4000),
      fullText: rawText.substring(0, 12000),
      extractionStatus: rawText === 'TEXT_EXTRACTION_FAILED' ? 'FAILED' : 'SUCCESS',
      expiryDatesFound: expiryMatches
    }
  }
};

const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let validation;
try {
  validation = JSON.parse(cleanText);
} catch (err) {
  const match = cleanText.match(/\{[\s\S]*\}/);
  if (match) {
    try { validation = JSON.parse(match[0]); }
    catch (e2) {
      validation = {
        docId: 'PARSE_ERROR',
        complianceStatus: 'INCOMPLETE_DATA',
        overallRiskLevel: 'HIGH',
        confidenceScore: 0,
        criticalFlags: ['AI response parse failed — manual review required'],
        remediationSteps: ['Resubmit document for validation'],
        documentSummary: 'Validation could not be completed due to a processing error.',
        requiresLegalReview: true,
        autoApprovable: false
      };
    }
  }
}

const upstream = $('Classify & Prepare Document').item.json;

return {
  json: {
    case: upstream.case,
    document: upstream.document,
    validation,
    validatedAt: new Date().toISOString()
  }
};

const items = $input.all();
if (items.length === 0) return [{ json: { error: 'No validation results to aggregate' } }];

const caseInfo = items[0].json.case;

// Mandatory document checklist per transaction type + jurisdiction
const MANDATORY_DOCS = {
  SALE: {
    NSW: ['CONTRACT_OF_SALE', 'CERTIFICATE_OF_TITLE', 'VENDOR_DISCLOSURE', 'PLANNING_CERTIFICATE'],
    VIC: ['CONTRACT_OF_SALE', 'CERTIFICATE_OF_TITLE', 'VENDOR_DISCLOSURE', 'BUILDING_PEST_REPORT'],
    QLD: ['CONTRACT_OF_SALE', 'CERTIFICATE_OF_TITLE', 'BUILDING_PEST_REPORT'],
    DEFAULT: ['CONTRACT_OF_SALE', 'CERTIFICATE_OF_TITLE']
  },
  PURCHASE: {
    NSW: ['CONTRACT_OF_SALE', 'BUILDING_PEST_REPORT'],
    DEFAULT: ['CONTRACT_OF_SALE']
  },
  LEASE: {
    DEFAULT: ['LEASE_AGREEMENT', 'SAFETY_CERTIFICATE']
  }
};

const txType = caseInfo.transactionType || 'SALE';
const jurisdiction = caseInfo.jurisdiction || 'NSW';
const mandatoryList = MANDATORY_DOCS[txType]?.[jurisdiction]
  || MANDATORY_DOCS[txType]?.DEFAULT
  || MANDATORY_DOCS.SALE.DEFAULT;

// Collect all confirmed/detected doc types submitted
const submittedTypes = items.map(i =>
  i.json.validation?.confirmedType || i.json.document?.detectedType || 'UNKNOWN'
);

// Check for missing mandatory docs
const missingMandatory = mandatoryList.filter(req => !submittedTypes.includes(req));

// Build per-document summaries
const documentResults = items.map(item => ({
  docId: item.json.document?.docId,
  name: item.json.document?.name,
  confirmedType: item.json.validation?.confirmedType || item.json.document?.detectedType,
  complianceStatus: item.json.validation?.complianceStatus || 'INCOMPLETE_DATA',
  overallRiskLevel: item.json.validation?.overallRiskLevel || 'HIGH',
  isExpired: item.json.validation?.isExpired || false,
  criticalFlags: item.json.validation?.criticalFlags || [],
  failedChecks: item.json.validation?.failedChecks || [],
  warnings: item.json.validation?.warnings || [],
  remediationSteps: item.json.validation?.remediationSteps || [],
  requiresLegalReview: item.json.validation?.requiresLegalReview || false,
  autoApprovable: item.json.validation?.autoApprovable || false,
  documentSummary: item.json.validation?.documentSummary || ''
}));

// Compute overall case status
const hasCritical = documentResults.some(d => d.overallRiskLevel === 'CRITICAL' || d.criticalFlags?.length > 0);
const hasFailed = documentResults.some(d => d.complianceStatus === 'FAIL');
const hasExpired = documentResults.some(d => d.isExpired);
const allPassed = documentResults.every(d => d.complianceStatus === 'PASS');
const hasIncomplete = documentResults.some(d => d.complianceStatus === 'INCOMPLETE_DATA');
const missingMandatoryExists = missingMandatory.length > 0;

const overallStatus = hasCritical || missingMandatoryExists
  ? 'FAIL'
  : hasFailed || hasExpired
    ? 'FAIL'
    : hasIncomplete
      ? 'REQUIRES_REVIEW'
      : allPassed
        ? 'PASS'
        : 'REQUIRES_REVIEW';

const criticalCount = documentResults.filter(d => d.overallRiskLevel === 'CRITICAL').length;
const highCount = documentResults.filter(d => d.overallRiskLevel === 'HIGH').length;
const passCount = documentResults.filter(d => d.complianceStatus === 'PASS').length;
const failCount = documentResults.filter(d => d.complianceStatus === 'FAIL').length;

// Build flat remediation list across all docs
const allRemediations = [];
if (missingMandatory.length > 0) {
  allRemediations.push(`MISSING DOCUMENTS: Submit the following mandatory documents — ${missingMandatory.join(', ')}`);
}
for (const doc of documentResults) {
  for (const step of (doc.remediationSteps || [])) {
    allRemediations.push(`[${doc.name}] ${step}`);
  }
}

return [{
  json: {
    case: caseInfo,
    overallStatus,
    summary: {
      totalDocuments: documentResults.length,
      passed: passCount,
      failed: failCount,
      requiresReview: documentResults.filter(d => d.complianceStatus === 'REQUIRES_REVIEW').length,
      expired: documentResults.filter(d => d.isExpired).length,
      criticalIssues: criticalCount,
      highRiskDocs: highCount
    },
    missingMandatoryDocuments: missingMandatory,
    documentResults,
    allRemediationSteps: allRemediations,
    requiresLegalReview: documentResults.some(d => d.requiresLegalReview) || hasCritical,
    canAutoApprove: overallStatus === 'PASS' && documentResults.every(d => d.autoApprovable),
    aggregatedAt: new Date().toISOString()
  }
}];

parameters.jsonBody:
={
  "channel": "{{ $json.overallStatus === 'FAIL' ? '#legal-critical' : '#legal-review' }}",
  "text": "🏠 Property Document Validation — {{ $json.overallStatus }}: {{ $json.case.caseId }}",
  "blocks": [
    {
      "type": "header",
      "text": { "type": "plain_text", "text": "📋 {{ $json.overallStatus }} — {{ $json.case.caseId }}" }
    },
    {
      "type": "section",
      "fields": [
        { "type": "mrkdwn", "text": "*Property:*\n{{ $json.case.propertyAddress }}" },
        { "type": "mrkdwn", "text": "*Transaction:*\n{{ $json.case.transactionType }} ({{ $json.case.jurisdiction }})" },
        { "type": "mrkdwn", "text": "*Submitter:*\n{{ $json.case.submitterEmail }}" },
        { "type": "mrkdwn", "text": "*Docs Reviewed:*\n{{ $json.summary.totalDocuments }} ({{ $json.summary.passed }} passed, {{ $json.summary.failed }} failed)" },
        { "type": "mrkdwn", "text": "*Critical Issues:*\n{{ $json.summary.criticalIssues }}" },
        { "type": "mrkdwn", "text": "*Missing Mandatory:*\n{{ $json.missingMandatoryDocuments.length > 0 ? $json.missingMandatoryDocuments.join(', ') : 'None' }}" }
      ]
    },
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "*Top Remediation Actions:*\n{{ $json.allRemediationSteps.slice(0,3).map((s,i) => (i+1)+'. '+s).join('\\n') || 'No actions required' }}" }
    },
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "*Legal Review Required:* {{ $json.requiresLegalReview ? '🔴 YES — Assign solicitor immediately' : '🟢 No' }}" }
    }
  ]
}
